import{b as t,I as n,g as i,j as s}from"./chunks/framework.DUo3J_Qe.js";const a="/geo-ml/learning/concepts/ai.png",g=JSON.parse('{"title":"Utilité","description":"","frontmatter":{},"headers":[],"relativePath":"fr/learning/concepts/utility.md","filePath":"fr/learning/concepts/utility.md"}'),r={name:"fr/learning/concepts/utility.md"};function o(l,e,c,p,u,m){return n(),i("div",null,[...e[0]||(e[0]=[s('<h1 id="utilite" tabindex="-1">Utilité <a class="header-anchor" href="#utilite" aria-label="Permalink to &quot;Utilité&quot;">​</a></h1><p>Le <strong>Machine Learning (ML)</strong> est un sous-domaine de l’intelligence artificielle qui permet aux machines <strong>d’apprendre automatiquement à partir de données</strong>, sans être explicitement programmées.</p><p><img src="'+a+'" alt="AI"></p><p>En résumé, un algorithme de machine learning n’est <strong>pas programmé explicitement</strong> pour chaque décision. Il apprend quelles actions sont optimales à partir des données existantes.</p><h2 id="pourquoi-utiliser-le-machine-learning" tabindex="-1">Pourquoi utiliser le machine learning ? <a class="header-anchor" href="#pourquoi-utiliser-le-machine-learning" aria-label="Permalink to &quot;Pourquoi utiliser le machine learning ?&quot;">​</a></h2><p>Le machine learning est indispensable pour traiter :</p><ul><li>Des problèmes <strong>trop complexes</strong> pour être codés manuellement.</li><li>Des volumes de données <strong>trop importants</strong> pour une analyse humaine.</li><li>Des tâches qui nécessitent de la <strong>prédiction ou de l’automatisation</strong>.</li></ul><div class="info custom-block"><p class="custom-block-title">👉 Exemples</p><p>filtrage spam, lecture d’adresses manuscrites par les services postaux, reconnaissance de l’écriture, prédiction financière, etc.</p></div><h2 id="l-importance-des-donnees" tabindex="-1">L’importance des données <a class="header-anchor" href="#l-importance-des-donnees" aria-label="Permalink to &quot;L’importance des données&quot;">​</a></h2><p>L’efficacité du machine learning dépend <strong>principalement de la qualité des données</strong> :</p><ul><li>Nettoyer et organiser les données est souvent la tâche la plus longue et la plus critique.</li><li>La mise en œuvre de l’algorithme est généralement simple grâce aux bibliothèques Python comme <strong>Scikit-learn</strong>.</li><li>Développer de nouveaux algorithmes est rarement nécessaire : la plupart des solutions sont déjà disponibles et bien documentées.</li></ul><blockquote><p><em>Un modèle n’est jamais meilleur que ses données.</em></p></blockquote>',12)])])}const h=t(r,[["render",o]]);export{g as __pageData,h as default};
